import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { useLiveListSync } from './useLiveListSync';
import { usePersistentState } from './usePersistentState';

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    fetchModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: any) => {

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);
    const [modelRequiredData, setModelRequiredData] = useState<any | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);

    const [launchedResults, setLaunchedResults] = usePersistentState<MatchResult[]>(`identificapix-launched${userSuffix}`, [], true);

    const processingFilesRef = useRef<Set<string>>(new Set());

    const { persistTransactions, clearRemoteList, hydrate } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const findMatchResult = useCallback((txId: string) => {
        return matchResults.find(r => r.transaction.id === txId);
    }, [matchResults]);

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueResults = Array.from(new Map(results.map(r => [r.transaction.id, r])).values());

        // FILTRAGEM RÍGIDA POR MONTANTE EFETIVO (Elimina Duplicação Cruzada)
        const incomeResults = uniqueResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
            return val >= 0;
        });

        const expenseResults = uniqueResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
            return val < 0;
        });

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File, base64?: string) => {
        const processKey = `${bankId}-${fileName}`;
        if (processingFilesRef.current.has(processKey)) {
            return;
        }

        processingFilesRef.current.add(processKey);
        setIsLoading(true);

        try {
            if (fetchModels) await fetchModels();

            // V3: Passamos o base64 para o processador garantir visão computacional
            const executorResult = await processFileContent(content, fileName, fileModels, customIgnoreKeywords, base64);

            const transactions = Array.isArray(executorResult?.transactions) ? executorResult.transactions : [];

            if (executorResult.status === 'MODEL_REQUIRED' || (transactions.length === 0 && bankId !== 'gmail-sync')) {
                console.log("[Pipeline:GOV] Interrompendo por falta de modelo ou extração vazia.");
                setModelRequiredData({
                    ...executorResult,
                    status: 'MODEL_REQUIRED',
                    fileName,
                    bankId
                });
                setIsLoading(false);
                processingFilesRef.current.delete(processKey);
                return;
            }

            if (transactions.length === 0) {
                showToast("Nenhuma transação extraída do arquivo.", "error");
                setIsLoading(false);
                processingFilesRef.current.delete(processKey);
                return;
            }

            const stats = await persistTransactions(bankId, transactions);
            showToast(stats.added === 0 ? "Lista Sincronizada." : `Sucesso! Total: ${stats.total}`, "success");
            await hydrate();

        } catch (error: any) {
            console.error("[Pipeline:ERROR] Falha crítica no upload:", error);
            showToast("Erro no processamento do arquivo.", "error");
        } finally {
            processingFilesRef.current.delete(processKey);
            setIsLoading(false);
        }
    }, [fileModels, fetchModels, customIgnoreKeywords, persistTransactions, showToast, hydrate, setIsLoading]);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        const gmailKey = `gmail-sync-active`;
        if (processingFilesRef.current.has(gmailKey)) return;

        processingFilesRef.current.add(gmailKey);
        setIsLoading(true);

        try {
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);
            const stats = await persistTransactions('gmail-sync', result.transactions);
            showToast(`Gmail sincronizado! Total: ${stats.total}`, "success");
            await hydrate();
        } finally {
            processingFilesRef.current.delete(gmailKey);
            setIsLoading(false);
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading, hydrate]);

    const removeBankStatementFile = useCallback(async (bankId: string) => {
        setIsLoading(true);
        try {
            await clearRemoteList(bankId);
            showToast("Lista removida do sistema.", "success");
        } catch (e) {
            showToast("Erro ao remover lista.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [clearRemoteList, showToast, setIsLoading]);

    const resetReconciliation = useCallback(async () => {
        setIsLoading(true);
        try {
            await clearRemoteList('all');
            setMatchResults([]);
            setReportPreviewData(null);
            setContributorFiles([]);
            setHasActiveSession(false);
            showToast("Sistema reiniciado.", "success");
            setActiveView('upload');
        } finally {
            setIsLoading(false);
        }
    }, [clearRemoteList, showToast, setActiveView, setIsLoading]);

    const markAsLaunched = useCallback((txId: string) => {
        setMatchResults(prev => {
            const itemIndex = prev.findIndex(r => r.transaction.id === txId);
            if (itemIndex === -1) return prev;

            const item = prev[itemIndex];

            setLaunchedResults(launched => [{ 
                ...item, 
                launchedAt: new Date().toISOString() 
            }, ...launched]);

            const next = prev.filter(r => r.transaction.id !== txId);
            setTimeout(() => regenerateReportPreview(next), 0);
            return next;
        });
    }, [setMatchResults, setLaunchedResults, regenerateReportPreview]);

    const undoLaunch = useCallback((txId: string) => {
        setLaunchedResults(prevLaunched => {
            const item = prevLaunched.find(r => r.transaction.id === txId);
            if (!item) return prevLaunched;

            // Remove from launched
            const nextLaunched = prevLaunched.filter(r => r.transaction.id !== txId);

            // Add back to matchResults if it doesn't already exist (unlikely but safe)
            setMatchResults(prevResults => {
                if (prevResults.some(r => r.transaction.id === txId)) return prevResults;
                const updatedResults = [...prevResults, item];
                setTimeout(() => regenerateReportPreview(updatedResults), 0);
                return updatedResults;
            });

            return nextLaunched;
        });
        showToast("Lançamento desfeito.", "success");
    }, [setMatchResults, setLaunchedResults, regenerateReportPreview, showToast]);

    const deleteLaunchedItem = useCallback((txId: string) => {
        setLaunchedResults(prev => prev.filter(r => r.transaction.id !== txId));
        showToast("Item removido do histórico de lançados.", "success");
    }, [setLaunchedResults, showToast]);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        modelRequiredData, setModelRequiredData,
        loadingAiId, setLoadingAiId, findMatchResult,
        launchedResults, setLaunchedResults, markAsLaunched, undoLaunch, deleteLaunchedItem,
        importGmailTransactions, handleStatementUpload, 
        handleContributorsUpload: (content: string, fileName: string, churchId: string) => {
             const church = churches.find((c: any) => c.id === churchId);
             const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
             setContributorFiles(prev => [...prev.filter(f => f.churchId !== churchId), { church, churchId, contributors, fileName }]);
             showToast(`Lista carregada (${contributors.length} nomes).`, "success");
        },
        removeBankStatementFile,
        removeContributorFile: (churchId: string) => setContributorFiles(prev => prev.filter(f => f.churchId !== churchId)),
        toggleBankSelection: (id: string) => setSelectedBankIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]),
        handleCompare: async () => {
            setIsLoading(true);
            const allTransactions = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId)).flatMap(f => f.processedTransactions || []);

            if (allTransactions.length === 0) { 
                showToast("Sem dados para processar.", "error"); 
                setIsLoading(false); 
                return; 
            }

            const results = matchTransactions(
                allTransactions, 
                contributorFiles, 
                { similarityThreshold: similarityLevel, dayTolerance: dayTolerance }, 
                learnedAssociations, 
                churches, 
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            setActiveView('reports');
            setIsLoading(false);
            showToast("Processamento concluído!", "success");
        },
        resetReconciliation,
        updateReportData: (updatedRow: MatchResult) => {
            setMatchResults(prev => {
                const next = [...prev];
                const idx = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
                if (idx !== -1) next[idx] = updatedRow;
                else next.push(updatedRow);
                regenerateReportPreview(next);
                return next;
            });
        },
        revertMatch: (txId: string) => {
            setMatchResults(prev => {
                const next = prev.map(r => r.transaction.id === txId ? { ...r, status: ReconciliationStatus.UNIDENTIFIED, contributor: null, church: PLACEHOLDER_CHURCH } : r);
                regenerateReportPreview(next);
                return next;
            });
        },
        closeManualIdentify: () => { setManualIdentificationTx(null); setBulkIdentificationTxs([]); },
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        },
        hydrate,
        setMatchResults,
        setReportPreviewData
    };
};

import { useCallback } from 'react';
import { ReconciliationStatus, MatchMethod, MatchResult } from '../types';
import { normalizeString, groupResultsByChurch } from '../services/processingService';

interface UseAiAutoIdentifyProps {
    reconciliation: any;
    referenceData: any;
    effectiveIgnoreKeywords: string[];
    setIsLoading: (loading: boolean) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
}

export const useAiAutoIdentify = ({
    reconciliation,
    referenceData,
    effectiveIgnoreKeywords,
    setIsLoading,
    showToast
}: UseAiAutoIdentifyProps) => {

    const runAiAutoIdentification = useCallback(() => {
        if (reconciliation.matchResults.length === 0) return;

        setIsLoading(true);
        let identifiedCount = 0;

        const currentResults = [...reconciliation.matchResults];
        const nextResults = currentResults.map(res => {
            if (res.status === ReconciliationStatus.UNIDENTIFIED) {
                const txDescNorm = normalizeString(res.transaction.description, effectiveIgnoreKeywords);
                const learned = referenceData.learnedAssociations.find((la: any) => la.normalizedDescription === txDescNorm);

                if (learned) {
                    const church = referenceData.churches.find((c: any) => c.id === learned.churchId);
                    if (church) {
                        identifiedCount++;
                        return {
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            church: church,
                            matchMethod: MatchMethod.LEARNED,
                            similarity: 100,
                            contributor: res.suggestion || { name: learned.contributorNormalizedName, amount: res.transaction.amount },
                            contributorAmount: res.transaction.amount,
                            suggestion: undefined
                        };
                    }
                }

                if (res.suggestion && (res.similarity || 0) >= 90) {
                    const churchId = (res.suggestion as any)._churchId || (res.suggestion as any).church?.id;
                    const church = referenceData.churches.find((c: any) => c.id === churchId);

                    if (church) {
                        identifiedCount++;
                        return {
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            contributor: res.suggestion,
                            church: church,
                            matchMethod: MatchMethod.AI,
                            similarity: res.similarity,
                            contributorAmount: res.suggestion.amount,
                            suggestion: undefined
                        };
                    }
                }
            }
            return res;
        });

        if (identifiedCount > 0) {
            reconciliation.setMatchResults(nextResults);

            // SEPARAÇÃO RÍGIDA POR MONTANTE EFETIVO
            const incomeResults = nextResults.filter(r => {
                const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
                return val >= 0;
            });

            const expenseResults = nextResults.filter(r => {
                const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
                return val < 0;
            });

            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(incomeResults),
                expenses: { 'all_expenses_group': expenseResults }
            });

            showToast(`${identifiedCount} transações identificadas automaticamente.`, "success");
        } else {
            showToast("Nenhuma sugestão de alta confiança encontrada.", "success");
        }

        setIsLoading(false);
    }, [reconciliation, referenceData, effectiveIgnoreKeywords, setIsLoading, showToast]);

    return { runAiAutoIdentification };
};

import { useCallback } from 'react';
import { MatchResult, Church, ReconciliationStatus, MatchMethod } from '../types';
// Fixed: Imported groupResultsByChurch from processingService instead of using require
import { groupResultsByChurch } from '../services/processingService';

interface UseReconciliationActionsProps {
  reconciliation: any;
  referenceData: any;
  showToast: (msg: string, type: 'success' | 'error') => void;
}

export const useReconciliationActions = ({
  reconciliation,
  referenceData,
  showToast
}: UseReconciliationActionsProps) => {

  const confirmManualIdentification = useCallback((txId: string, churchId: string) => {
    const church = referenceData.churches.find((c: Church) => c.id === churchId);
    if (!church) return;

    const originalResult = reconciliation.matchResults.find((r: MatchResult) => r.transaction.id === txId);
    if (!originalResult) return;

    const updatedResult: MatchResult = {
      ...originalResult,
      status: ReconciliationStatus.IDENTIFIED,
      church: church,
      matchMethod: MatchMethod.MANUAL,
      similarity: 100,
      divergence: undefined
    };

    reconciliation.updateReportData(updatedResult);
    referenceData.learnAssociation(updatedResult);

    reconciliation.closeManualIdentify();
    showToast("Identificado manualmente.", "success");
  }, [reconciliation, referenceData, showToast]);

  const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
    const church = referenceData.churches.find((c: Church) => c.id === churchId);
    if (!church) return;

    // 1. Cria uma nova lista baseada no estado atual para garantir imutabilidade e re-render
    const currentResults = [...reconciliation.matchResults];
    let affectedCount = 0;

    txIds.forEach(id => {
      const idx = currentResults.findIndex(r => r.transaction.id === id);
      if (idx !== -1) {
        const original = currentResults[idx];

        // 2. Cria o novo objeto de resultado para este item do lote
        const updated: MatchResult = {
          ...original,
          status: ReconciliationStatus.IDENTIFIED, // Muda para Identificado
          church, // Define a igreja escolhida
          matchMethod: MatchMethod.MANUAL,
          similarity: 100,
          contributorAmount: original.transaction.amount || original.contributor?.amount,
          divergence: undefined
        };

        currentResults[idx] = updated;

        // 3. Opcional: Aprende a associação para usos futuros automáticos
        referenceData.learnAssociation(updated);
        affectedCount++;
      }
    });

    // 4. Atualiza o estado principal do motor de reconciliação
    reconciliation.setMatchResults(currentResults);

    // 5. Força a regeneração do preview (necessário para atualizar as abas de Relatórios)
    if (reconciliation.setReportPreviewData) {
        // SEPARAÇÃO RÍGIDA POR MONTANTE EFETIVO (Elimina Duplicação)
        const incomeResults = currentResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
            return val >= 0;
        });

        const expenseResults = currentResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
            return val < 0;
        });

        reconciliation.setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }

    // 6. Fecha o modal e limpa a seleção
    reconciliation.closeManualIdentify();
    showToast(`${affectedCount} registros identificados para ${church.name}.`, "success");
  }, [reconciliation, referenceData, showToast]);

  const undoIdentification = useCallback((txId: string) => {
    reconciliation.revertMatch(txId);
    showToast("Identificação desfeita.", "success");
  }, [reconciliation, showToast]);

  return {
    confirmManualIdentification,
    confirmBulkManualIdentification,
    undoIdentification
  };
};

import { Contributor, MatchResult, Church, Transaction, ReconciliationStatus, MatchMethod } from '../../types';
import { normalizeString, extractIdentifyingCode, PLACEHOLDER_CHURCH } from '../utils/parsingUtils';

/**
 * Calcula a similaridade valorizando códigos identificadores (DNA Numérico).
 */
export const calculateNameSimilarity = (description: string, contributor: Contributor, ignoreKeywords: string[] = []): number => {
    const txCode = extractIdentifyingCode(description);
    const contribCode = extractIdentifyingCode(contributor.name) || (contributor.id && extractIdentifyingCode(contributor.id));

    // REGRA DE OURO: Se o código numérico (DNA) bater, o match é 100%
    if (txCode && contribCode && txCode.length >= 4 && contribCode.length >= 4) {
        if (txCode.includes(contribCode) || contribCode.includes(txCode)) {
            return 100; // Prioridade absoluta ao código
        }
    }

    const txNorm = normalizeString(description, ignoreKeywords);
    const contribNorm = contributor.normalizedName || normalizeString(contributor.name, ignoreKeywords);

    if (!txNorm || !contribNorm) return 0;

    const txTokens = txNorm.split(/\s+/).filter(t => t.length > 2);
    const contribTokens = contribNorm.split(/\s+/).filter(t => t.length > 2);

    if (txTokens.length === 0 || contribTokens.length === 0) {
        return txNorm === contribNorm ? 100 : 0;
    }

    const txSet = new Set(txTokens);
    const contribSet = new Set(contribTokens);
    const intersection = [...txSet].filter(w => contribSet.has(w)).length;

    return (2 * intersection) / (txSet.size + contribSet.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: any[] = [],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: any[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    const contributorsByChurch = new Map<string, any[]>();

    if (contributorFiles && contributorFiles.length > 0) {
        contributorFiles.forEach((file: any) => {
            const churchId = file.church.id;
            const list = file.contributors.map((c: any) => ({ 
                ...c, 
                church: file.church,
                _churchId: churchId,
                _internalId: c.id || `contrib-${churchId}-${normalizeString(c.name).replace(/\s/g, '')}`
            }));
            contributorsByChurch.set(churchId, list);
        });
    }

    const allContributorsFlat = Array.from(contributorsByChurch.values()).flat();
    const finalResults: MatchResult[] = [];
    const usedContributors = new Set<string>();

    transactions.forEach(tx => {
        const txDescNormalized = normalizeString(tx.description, customIgnoreKeywords);
        const currentBankId = tx.bank_id || 'virtual';

        let matchResult: MatchResult = {
            transaction: tx,
            contributor: null,
            status: ReconciliationStatus.UNIDENTIFIED,
            church: PLACEHOLDER_CHURCH,
            similarity: 0,
            contributionType: tx.contributionType,
            paymentMethod: tx.paymentMethod
        };

        // PRIORIDADE 1: Aprendizado Individual por Lista Viva (bankId)
        const learned = learnedAssociations.find((la: any) => 
            la.normalizedDescription === txDescNormalized && 
            (la.bankId === currentBankId || la.bankId === 'global')
        );

        if (learned && learned.churchId) {
            const church = churches.find(c => c.id === learned.churchId);
            if (church) {
                matchResult = {
                    ...matchResult,
                    status: ReconciliationStatus.IDENTIFIED,
                    church: church,
                    matchMethod: MatchMethod.LEARNED,
                    similarity: 100,
                    contributor: { 
                        name: learned.contributorNormalizedName, 
                        amount: tx.amount,
                        cleanedName: learned.contributorNormalizedName
                    },
                    contributorAmount: tx.amount
                };
                finalResults.push(matchResult);
                return;
            }
        }

        // PRIORIDADE 2: Match por Similaridade com DNA Numérico
        if (allContributorsFlat.length > 0) {
            let bestMatch: any = null;
            let highestScore = 0;

            allContributorsFlat.forEach((contrib: any) => {
                const score = calculateNameSimilarity(tx.description, contrib, customIgnoreKeywords);
                if (score > highestScore) {
                    highestScore = score;
                    bestMatch = contrib;
                }
            });

            if (bestMatch && highestScore >= (options.similarityThreshold || 55)) {
                usedContributors.add(bestMatch._internalId);
                matchResult = {
                    ...matchResult,
                    status: ReconciliationStatus.IDENTIFIED,
                    contributor: bestMatch,
                    church: bestMatch.church,
                    matchMethod: MatchMethod.AI,
                    similarity: highestScore,
                    contributorAmount: bestMatch.amount,
                    contributionType: bestMatch.contributionType || tx.contributionType,
                    paymentMethod: bestMatch.paymentMethod || tx.paymentMethod
                };
            } else if (bestMatch && highestScore >= 25) {
                matchResult.suggestion = bestMatch;
                matchResult.similarity = highestScore;
            }
        }

        finalResults.push(matchResult);
    });

    if (allContributorsFlat.length > 0) {
        allContributorsFlat.forEach((contrib: any) => {
            if (!usedContributors.has(contrib._internalId)) {
                // FIX: O amount da transaction virtual do Ghost DEVE refletir o sinal do contribuinte
                // Isso evita que itens negativos (saídas) caiam na aba de entradas por terem amount 0.
                const ghostAmount = contrib.amount || 0;

                finalResults.push({
                    transaction: {
                        id: `ghost-${contrib._internalId}`,
                        date: contrib.date || new Date().toISOString().split('T')[0],
                        description: contrib.name,
                        rawDescription: contrib.name,
                        amount: ghostAmount, // Antes era 0 fixo, causando erro de filtragem
                        cleanedDescription: contrib.name,
                        contributionType: contrib.contributionType,
                        paymentMethod: contrib.paymentMethod,
                        originalAmount: String(ghostAmount)
                    },
                    contributor: { ...contrib, cleanedName: contrib.name },
                    status: ReconciliationStatus.PENDING,
                    church: contrib.church,
                    matchMethod: MatchMethod.MANUAL,
                    similarity: 0,
                    contributorAmount: ghostAmount
                });
            }
        });
    }

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): Record<string, MatchResult[]> => {
    const grouped: Record<string, MatchResult[]> = {};
    results.forEach(r => {
        let key = 'unidentified';
        if ((r.status === ReconciliationStatus.IDENTIFIED || r.status === ReconciliationStatus.PENDING) && r.church?.id) {
            key = r.church.id;
        }
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { useLiveListSync } from './useLiveListSync';
import { usePersistentState } from './usePersistentState';

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    fetchModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: any) => {

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);
    const [modelRequiredData, setModelRequiredData] = useState<any | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);

    const [launchedResults, setLaunchedResults] = usePersistentState<MatchResult[]>(`identificapix-launched${userSuffix}`, [], true);

    const processingFilesRef = useRef<Set<string>>(new Set());

    const { persistTransactions, clearRemoteList, hydrate } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const findMatchResult = useCallback((txId: string) => {
        return matchResults.find(r => r.transaction.id === txId);
    }, [matchResults]);

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueResults = Array.from(new Map(results.map(r => [r.transaction.id, r])).values());

        // FILTRAGEM RÍGIDA E DEFINITIVA
        // Para registros PENDING (Ghosts), usamos o valor do contribuinte para decidir a categoria.
        const incomeResults = uniqueResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING 
                ? (r.contributorAmount || r.contributor?.amount || 0) 
                : r.transaction.amount;
            return val > 0; // Estritamente maior que zero para Entradas
        });

        const expenseResults = uniqueResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING 
                ? (r.contributorAmount || r.contributor?.amount || 0) 
                : r.transaction.amount;
            return val < 0; // Estritamente menor que zero para Saídas
        });

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File, base64?: string) => {
        const processKey = `${bankId}-${fileName}`;
        if (processingFilesRef.current.has(processKey)) {
            return;
        }

        processingFilesRef.current.add(processKey);
        setIsLoading(true);

        try {
            if (fetchModels) await fetchModels();

            // V3: Passamos o base64 para o processador garantir visão computacional
            const executorResult = await processFileContent(content, fileName, fileModels, customIgnoreKeywords, base64);

            const transactions = Array.isArray(executorResult?.transactions) ? executorResult.transactions : [];

            if (executorResult.status === 'MODEL_REQUIRED' || (transactions.length === 0 && bankId !== 'gmail-sync')) {
                console.log("[Pipeline:GOV] Interrompendo por falta de modelo ou extração vazia.");
                setModelRequiredData({
                    ...executorResult,
                    status: 'MODEL_REQUIRED',
                    fileName,
                    bankId
                });
                setIsLoading(false);
                processingFilesRef.current.delete(processKey);
                return;
            }

            if (transactions.length === 0) {
                showToast("Nenhuma transação extraída do arquivo.", "error");
                setIsLoading(false);
                processingFilesRef.current.delete(processKey);
                return;
            }

            const stats = await persistTransactions(bankId, transactions);
            showToast(stats.added === 0 ? "Lista Sincronizada." : `Sucesso! Total: ${stats.total}`, "success");
            await hydrate();

        } catch (error: any) {
            console.error("[Pipeline:ERROR] Falha crítica no upload:", error);
            showToast("Erro no processamento do arquivo.", "error");
        } finally {
            processingFilesRef.current.delete(processKey);
            setIsLoading(false);
        }
    }, [fileModels, fetchModels, customIgnoreKeywords, persistTransactions, showToast, hydrate, setIsLoading]);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        const gmailKey = `gmail-sync-active`;
        if (processingFilesRef.current.has(gmailKey)) return;

        processingFilesRef.current.add(gmailKey);
        setIsLoading(true);

        try {
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);
            const stats = await persistTransactions('gmail-sync', result.transactions);
            showToast(`Gmail sincronizado! Total: ${stats.total}`, "success");
            await hydrate();
        } finally {
            processingFilesRef.current.delete(gmailKey);
            setIsLoading(false);
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading, hydrate]);

    const removeBankStatementFile = useCallback(async (bankId: string) => {
        setIsLoading(true);
        try {
            await clearRemoteList(bankId);
            showToast("Lista removida do sistema.", "success");
        } catch (e) {
            showToast("Erro ao remover lista.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [clearRemoteList, showToast, setIsLoading]);

    const resetReconciliation = useCallback(async () => {
        setIsLoading(true);
        try {
            await clearRemoteList('all');
            setMatchResults([]);
            setReportPreviewData(null);
            setContributorFiles([]);
            setHasActiveSession(false);
            showToast("Sistema reiniciado.", "success");
            setActiveView('upload');
        } finally {
            setIsLoading(false);
        }
    }, [clearRemoteList, showToast, setActiveView, setIsLoading]);

    const markAsLaunched = useCallback((txId: string) => {
        setMatchResults(prev => {
            const itemIndex = prev.findIndex(r => r.transaction.id === txId);
            if (itemIndex === -1) return prev;

            const item = prev[itemIndex];

            setLaunchedResults(launched => [{ 
                ...item, 
                launchedAt: new Date().toISOString() 
            }, ...launched]);

            const next = prev.filter(r => r.transaction.id !== txId);
            setTimeout(() => regenerateReportPreview(next), 0);
            return next;
        });
    }, [setMatchResults, setLaunchedResults, regenerateReportPreview]);

    const undoLaunch = useCallback((txId: string) => {
        setLaunchedResults(prevLaunched => {
            const item = prevLaunched.find(r => r.transaction.id === txId);
            if (!item) return prevLaunched;

            // Remove from launched
            const nextLaunched = prevLaunched.filter(r => r.transaction.id !== txId);

            // Add back to matchResults if it doesn't already exist (unlikely but safe)
            setMatchResults(prevResults => {
                if (prevResults.some(r => r.transaction.id === txId)) return prevResults;
                const updatedResults = [...prevResults, item];
                setTimeout(() => regenerateReportPreview(updatedResults), 0);
                return updatedResults;
            });

            return nextLaunched;
        });
        showToast("Lançamento desfeito.", "success");
    }, [setMatchResults, setLaunchedResults, regenerateReportPreview, showToast]);

    const deleteLaunchedItem = useCallback((txId: string) => {
        setLaunchedResults(prev => prev.filter(r => r.transaction.id !== txId));
        showToast("Item removido do histórico de lançados.", "success");
    }, [setLaunchedResults, showToast]);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        modelRequiredData, setModelRequiredData,
        loadingAiId, setLoadingAiId, findMatchResult,
        launchedResults, setLaunchedResults, markAsLaunched, undoLaunch, deleteLaunchedItem,
        importGmailTransactions, handleStatementUpload, 
        handleContributorsUpload: (content: string, fileName: string, churchId: string) => {
             const church = churches.find((c: any) => c.id === churchId);
             const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
             setContributorFiles(prev => [...prev.filter(f => f.churchId !== churchId), { church, churchId, contributors, fileName }]);
             showToast(`Lista carregada (${contributors.length} nomes).`, "success");
        },
        removeBankStatementFile,
        removeContributorFile: (churchId: string) => setContributorFiles(prev => prev.filter(f => f.churchId !== churchId)),
        toggleBankSelection: (id: string) => setSelectedBankIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]),
        handleCompare: async () => {
            setIsLoading(true);
            const allTransactions = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId)).flatMap(f => f.processedTransactions || []);

            if (allTransactions.length === 0) { 
                showToast("Sem dados para processar.", "error"); 
                setIsLoading(false); 
                return; 
            }

            const results = matchTransactions(
                allTransactions, 
                contributorFiles, 
                { similarityThreshold: similarityLevel, dayTolerance: dayTolerance }, 
                learnedAssociations, 
                churches, 
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            setActiveView('reports');
            setIsLoading(false);
            showToast("Processamento concluído!", "success");
        },
        resetReconciliation,
        updateReportData: (updatedRow: MatchResult) => {
            setMatchResults(prev => {
                const next = [...prev];
                const idx = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
                if (idx !== -1) next[idx] = updatedRow;
                else next.push(updatedRow);
                regenerateReportPreview(next);
                return next;
            });
        },
        revertMatch: (txId: string) => {
            setMatchResults(prev => {
                const next = prev.map(r => r.transaction.id === txId ? { ...r, status: ReconciliationStatus.UNIDENTIFIED, contributor: null, church: PLACEHOLDER_CHURCH } : r);
                regenerateReportPreview(next);
                return next;
            });
        },
        closeManualIdentify: () => { setManualIdentificationTx(null); setBulkIdentificationTxs([]); },
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        },
        hydrate,
        setMatchResults,
        setReportPreviewData
    };
};

import React, { memo, useContext, useState, useCallback, useEffect } from 'react';
import { MatchResult } from '../types';
import { formatCurrency, formatDate } from '../utils/formatters';
import { useTranslation } from '../contexts/I18nContext';
import { AppContext } from '../contexts/AppContext';
import { SparklesIcon, UserPlusIcon, BrainIcon, ExclamationTriangleIcon, BanknotesIcon, UserIcon, CheckCircleIcon, BuildingOfficeIcon } from './Icons';
import { BulkActionToolbar } from './BulkActionToolbar';
import { NameResolver } from '../core/processors/NameResolver';

interface ResultsTableProps {
  results: MatchResult[];
  onManualIdentify: (transactionId: string) => void;
  loadingAiId: string | null;
  currentPage?: number;
  totalPages?: number;
  onPageChange?: (page: number) => void;
}

const MatchMethodIcon: React.FC<{ method: MatchResult['matchMethod'] }> = ({ method }) => {
    const { t } = useTranslation();
    if (!method) return null;

    const iconMap = {
        LEARNED: { Icon: BrainIcon, tooltip: t('tooltip.learned'), color: 'text-purple-500 bg-purple-50 dark:bg-purple-900/30 dark:text-purple-400' },
        AI: { Icon: SparklesIcon, tooltip: t('tooltip.ai'), color: 'text-teal-500 bg-teal-50 dark:bg-teal-900/30 dark:text-teal-400' },
        MANUAL: { Icon: UserPlusIcon, tooltip: t('tooltip.manual'), color: 'text-blue-500 bg-blue-50 dark:bg-blue-900/30 dark:text-blue-400' },
        AUTOMATIC: null,
        TEMPLATE: null
    };

    const config = iconMap[method] || iconMap.AUTOMATIC;
    if (!config) return null;

    return (
        <span className={`ml-1.5 p-1 rounded-md ${config.color} inline-flex items-center justify-center`} title={config.tooltip}>
            <config.Icon className="w-3 h-3" />
        </span>
    );
}

export const ResultsTable: React.FC<ResultsTableProps> = memo(({ results, onManualIdentify, loadingAiId, currentPage, totalPages, onPageChange }) => {
    const { t, language } = useTranslation();

    const [selectedIds, setSelectedIds] = useState<string[]>([]);

    useEffect(() => {
        setSelectedIds([]);
    }, [results.length]);

    const toggleSelection = useCallback((id: string) => {
        setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    }, []);

    const toggleAll = useCallback(() => {
        if (selectedIds.length === results.length && results.length > 0) {
            setSelectedIds([]);
        } else {
            setSelectedIds(results.map(r => r.transaction.id));
        }
    }, [results, selectedIds]);

    const getStatusBadge = (status: MatchResult['status'], method?: MatchResult['matchMethod']) => {
        if (status === 'NÃO IDENTIFICADO') {
            return (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold bg-amber-50 text-amber-700 border border-amber-100 dark:bg-amber-900/30 dark:text-amber-400 dark:border-amber-800 uppercase tracking-wide whitespace-nowrap">
                    Pendente
                </span>
            );
        }
        if (status === 'PENDENTE') {
            return (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold bg-slate-100 text-slate-500 border border-slate-200 dark:bg-slate-700 dark:text-slate-300 dark:border-slate-600 uppercase tracking-wide whitespace-nowrap">
                    Não Localizado
                </span>
            );
        }
        let bgClass = 'bg-emerald-50 border-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:border-emerald-800 dark:text-emerald-400';
        let label = 'Auto';
        if (method === 'MANUAL') {
            bgClass = 'bg-blue-50 border-blue-100 text-blue-700 dark:bg-blue-900/30 dark:border-blue-800 dark:text-blue-400';
            label = 'Manual';
        } else if (method === 'AI') {
            bgClass = 'bg-purple-50 border-purple-100 text-purple-700 dark:bg-purple-900/30 dark:border-purple-800 dark:text-purple-400';
            label = 'IA';
        } else if (method === 'LEARNED') { label = 'Aprendido'; }
        return (
            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold border uppercase tracking-wide whitespace-nowrap ${bgClass}`}>
                {label}
            </span>
        );
    };

    return (
        <div className="bg-white dark:bg-slate-800 rounded-[1.5rem] shadow-card border border-slate-100 dark:border-slate-700 overflow-hidden mt-6 flex flex-col relative">
            <BulkActionToolbar selectedIds={selectedIds} onClear={() => setSelectedIds([])} />

            <div className="overflow-x-auto custom-scrollbar relative">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-slate-50/95 dark:bg-slate-800/95 border-b border-slate-200/60 dark:border-slate-700 backdrop-blur-md sticky top-0 z-20">
                        <tr>
                            <th scope="col" className="px-4 py-2.5 w-10 text-center">
                                <input 
                                    type="checkbox" 
                                    className="w-4 h-4 rounded-full border-slate-300 text-brand-blue focus:ring-brand-blue cursor-pointer accent-blue-600"
                                    onChange={toggleAll}
                                    checked={selectedIds.length > 0 && selectedIds.length === results.length}
                                />
                            </th>
                            <th scope="col" className="px-4 py-2.5 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[10%]">{t('table.date')}</th>
                            <th scope="col" className="px-4 py-2.5 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[22%]">Nome / Descrição</th>
                            <th scope="col" className="px-4 py-2.5 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[15%]">Igreja</th>
                            <th scope="col" className="px-4 py-2.5 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[12%]">Tipo</th>
                            <th scope="col" className="px-4 py-2.5 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[10%]">Forma</th>
                            <th scope="col" className="px-4 py-2.5 text-right text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[13%]">{t('table.amount')}</th>
                            <th scope="col" className="px-4 py-2.5 text-center text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[8%]">{t('table.status')}</th>
                            <th scope="col" className="px-4 py-2.5 text-center text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest w-[8%]">{t('table.actions')}</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-700/50">
                        {results.map(({ transaction, contributor, status, matchMethod, contributorAmount, contributionType, paymentMethod, divergence, church }) => {
                            const isGhost = status === 'PENDENTE';
                            const isSelected = selectedIds.includes(transaction.id);

                            // FIX: Para Ghosts, o valor efetivo SEMPRE deve vir do contributorAmount
                            const displayAmount = isGhost ? (contributorAmount || contributor?.amount || 0) : transaction.amount;
                            const isExpense = displayAmount < 0;

                            const rawDate = isGhost ? (contributor?.date || transaction.date) : transaction.date;
                            const displayDate = formatDate(rawDate);

                            const rawName = contributor?.cleanedName || contributor?.name || transaction.cleanedDescription || transaction.description;
                            const primaryName = NameResolver.formatDisplayName(rawName);

                            const displayType = contributor?.contributionType || contributionType || transaction.contributionType || '---';
                            const displayForm = contributor?.paymentMethod || paymentMethod || transaction.paymentMethod || '---';

                            return (
                                <tr key={transaction.id} className={`group hover:bg-slate-50/80 dark:hover:bg-slate-700/30 transition-all duration-200 ${isGhost ? 'opacity-70 bg-slate-50/30 dark:bg-slate-800/30' : ''} ${isSelected ? 'bg-blue-50/50 dark:bg-blue-900/10' : ''}`}>
                                    <td className="px-4 py-2.5 text-center">
                                        <input 
                                            type="checkbox" 
                                            className="w-4 h-4 rounded-full border-slate-300 text-brand-blue focus:ring-brand-blue cursor-pointer accent-blue-600"
                                            checked={isSelected}
                                            onChange={() => toggleSelection(transaction.id)}
                                        />
                                    </td>
                                    <td className="px-4 py-2.5 whitespace-nowrap font-mono text-[11px] text-slate-500 dark:text-slate-400 tabular-nums">{displayDate}</td>
                                    <td className="px-4 py-2.5">
                                        <div className="flex flex-col gap-1">
                                            <div className="flex items-center gap-2">
                                                {(contributor || isGhost) ? <UserIcon className="w-3.5 h-3.5 text-indigo-500 shrink-0" /> : <BanknotesIcon className="w-3.5 h-3.5 text-slate-400 shrink-0" />}
                                                <span className={`text-xs font-bold leading-tight break-words ${isGhost ? 'text-slate-500 dark:text-slate-400' : 'text-slate-800 dark:text-white'}`}>{primaryName}</span>
                                            </div>
                                            {isGhost && <span className="text-[9px] text-red-400 pl-5 font-medium italic">Não encontrado no extrato</span>}
                                        </div>
                                    </td>
                                    <td className="px-4 py-2.5">
                                        <div className="flex items-center gap-2">
                                            <BuildingOfficeIcon className={`w-3.5 h-3.5 shrink-0 ${status === 'IDENTIFICADO' ? 'text-indigo-400' : 'text-slate-300'}`} />
                                            <span className={`text-[10px] font-bold uppercase break-words ${status === 'IDENTIFICADO' ? 'text-slate-700 dark:text-slate-300' : 'text-slate-400'}`}>
                                                {church?.name || '---'}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="px-4 py-2.5">
                                        <span className={`px-2 py-0.5 rounded-md text-[9px] font-black uppercase tracking-widest ${displayType !== '---' ? 'bg-indigo-50 text-indigo-700 border border-indigo-100 dark:bg-indigo-900/30' : 'text-slate-300 italic'}`}>{displayType}</span>
                                    </td>
                                    <td className="px-4 py-2.5">
                                        <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase">{displayForm}</span>
                                    </td>
                                    <td className="px-4 py-2.5 text-right font-mono text-xs font-bold tabular-nums">
                                        <span className={isExpense ? 'text-red-600 dark:text-red-400' : 'text-slate-900 dark:text-white'}>{formatCurrency(displayAmount, language)}</span>
                                    </td>
                                    <td className="px-4 py-2.5 text-center">
                                        <div className="flex items-center justify-center gap-1">
                                            {getStatusBadge(status, matchMethod)}
                                            {status === 'IDENTIFICADO' && <MatchMethodIcon method={matchMethod} />}
                                            {divergence && <span className="text-yellow-500 ml-1"><ExclamationTriangleIcon className="w-3 h-3"/></span>}
                                        </div>
                                    </td>
                                    <td className="px-4 py-2.5 text-center">
                                        {status === 'NÃO IDENTIFICADO' && (
                                            <button onClick={() => onManualIdentify(transaction.id)} className="p-1.5 rounded-lg bg-slate-100 text-slate-500 hover:bg-brand-blue hover:text-white opacity-0 group-hover:opacity-100 transition-all"><UserPlusIcon className="w-3.5 h-3.5" /></button>
                                        )}
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
});
